import SwiftUI

struct RadiationTypeLabelView: View {
    let value: Float?
    let radiationType: RadiationType

    var body: some View {
        label { valueString, unitString in
            RadiationLabelDefaultLayout(valueString: valueString, unitString: unitString)
        }
    }

    @ViewBuilder
    func label<Content: View>(
        @ViewBuilder _ build: @escaping (String, String) -> Content
    ) -> some View {
        switch radiationType {
        case .radiationLevel(.countRate):
            CountRateLabelView(value: value)
                .label(build)
        case .radiationLevel(.doseRate):
            DoseRateLabelView(value: value)
                .label(build)
        case .dose:
            DoseLabelView(value: value)
                .label(build)
        }
    }
}

