    let value: Float?
    let error: Float?
    let level: SignalizationAlarmLevel

    var body: some View {
        RadiationTypeLabelView(value: value, radiationType: .radiationLevel(radiationType))
            .label { value, unit in
                HStack(alignment: .top) {
                    VStack(alignment: .leading, spacing: 3) {
                        Text(radiationType.title)
                            .font(.system(size: 17, weight: .semibold))
                        Text(unit)
                            .foregroundStyle(.textSecondary)
                            .font(.system(size: 13))
                    }
                    .padding(.top, 5)
                    .padding(.leading, 8)

                    Spacer()
                    VStack(alignment: .trailing) {
                        Text(value)
                            .font(.system(size: 38, weight: .bold, design: .rounded))
                            .foregroundStyle(level.color)
                        if let error {
                            Text(verbatim: "±\(String(format: "%.1f", error))%")
                                .font(.system(size: 13))
                                .foregroundStyle(.textPrimary)
                        }
                    }
                    .padding(.trailing, 42)
                }
            }
    }
}

