//
//  DoseFormatted.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 22.05.2026.
//

import Foundation

enum DoseDisplayMode {
    case dose
    case rate(DoseRateSuffix)

    enum DoseRateSuffix {
        case hour
        case week

        var text: LocalizedStringResource {
            switch self {
            case .hour: .Localization.h
            case .week: .Localization.week
            }
        }
    }
}

struct DoseFormatted {

    let value: Float?
    let prefix: String
    let base: LocalizedStringResource
    let suffix: DoseDisplayMode.DoseRateSuffix?

    var unitString: String {
        let baseStr = String(localized: base)
        let suffixStr = suffix.map { "/\(String(localized: $0.text))" } ?? ""
        return "\(prefix)\(baseStr)\(suffixStr)"
    }

    init(rawValue: Float?, unit: Settings.DoseMeasurementUnit, mode: DoseDisplayMode) {
        base = unit.title

        switch mode {
        case .dose:
            suffix = nil
        case .rate(let rate):
            suffix = rate
        }

        guard let rawValue else {
            value = nil
            prefix = "μ"
            return
        }

        let scaled = rawValue * (unit == .rem ? 100 : 1)
        if scaled >= 1_000_000 {
            value = scaled / 1_000_000
            prefix = ""
        } else if scaled >= 1_000 {
            value = scaled / 1_000
            prefix = "m"
        } else {
            value = scaled
            prefix = "μ"
        }
    }
}

