import Foundation
import Combine
import FactoryKit

protocol ChartModelBuilder {
    /// Функция усреднения сырых данных
    /// - Parameter rawData: исходный массив сырых данных
    /// - Returns: усредненный массив сырых данных
    func averagingRawData(rawData: [RadiationLevelChartDataModel]) -> [RadiationLevelChartDataModel]
}

final class ChartModelBuilderImpl: ChartModelBuilder {

    @Injected(\.deviceConnectionManager) private var deviceConnectionManager

    private enum Consts {
        static let averaging = 6
        static let samplesPerSecond = 2
        static let windowSize = averaging * samplesPerSecond + 1
    }

    private var supportAveragingRawData: Bool = true
    private var cancellable: Set<AnyCancellable> = .init()

    init() {
        deviceConnectionManager.connectionSubject
            .compactMap { $0.readyDevice }
            .sink { [weak self] device in
                guard let self else { return }
                self.supportAveragingRawData = device.supportAveragingRawData
            }
            .store(in: &cancellable)
    }

    func averagingRawData(rawData: [RadiationLevelChartDataModel]) -> [RadiationLevelChartDataModel] {
        guard supportAveragingRawData, rawData.count >= Consts.windowSize else { return rawData }

        var averagedData: [RadiationLevelChartDataModel] = []
        averagedData.reserveCapacity(rawData.count - Consts.windowSize + 1)

        var sum: Float = rawData.prefix(Consts.windowSize).reduce(0) { $0 + $1.count }
        var startIndex = Consts.windowSize / Consts.samplesPerSecond

        averagedData.append(.init(count: max(sum / Float(Consts.windowSize), 0), time: rawData[startIndex].time))

        for index in Consts.windowSize..<rawData.count {
            sum += rawData[index].count - rawData[index - Consts.windowSize].count
            startIndex += 1
            averagedData.append(.init(count: max(sum / Float(Consts.windowSize), 0), time: rawData[startIndex].time))
        }
        return averagedData
    }
}

