import Foundation

struct RadiationLevelChartDataModel: Hashable, Comparable {

    let count: Float
    let time: Double

    static func == (lhs: RadiationLevelChartDataModel, rhs: RadiationLevelChartDataModel) -> Bool {
        lhs.time == rhs.time
    }

    static func < (lhs: RadiationLevelChartDataModel, rhs: RadiationLevelChartDataModel) -> Bool {
        lhs.time < rhs.time
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(time)
    }
}
